def make_plant(node_class):
    """
    Takes a PlantUML code and returns only valid PlantUML code wrapped in @startuml and @enduml tags.
    """
    def is_leaf_class(node_class):
        return node_class == "root"

    def is_element_class(node_class, element_type):
        return node_class == "member" or element_type == "attribute"

    def is_attribute_class(node_class, attribute_type):
        return node_class == "member"

    def is_value_class(node_class, value_type):
        return node_class == "member"

    def is_name_class(node_class, name_type):
        return node_class == "member"

    def is_node_class(node_class, node_type):
        return node_class == "member"

    def make_plant(node_class, node_type):
        """
        Takes a PlantUML code and returns only valid PlantUML code wrapped in @startuml and @enduml tags.
        """
        for tag in ["root", "member", "attribute"]:
            if not is_leaf_class(node_class) or not is_element_class(node_class, node_type):
                return False

        return True

    def make_plant(node_class):
        """
        Takes a PlantUML code and returns only valid PlantUML code wrapped in @startuml and @enduml tags.
        """
        for tag in ["member", "attribute"]:
            if not is_leaf_class(node_class, node_type):
                return False

        return True

    def make_plant(*nodes):
        """
        Takes a PlantUML code and returns only valid PlantUML code wrapped in @startuml and @enduml tags.
        """
        for node in nodes:
            if not is_leaf_class(node):
                return False

        return True

    def make_plant(node_type=None, node_value_type="none"):
        """
        Takes a PlantUML code and returns only valid PlantUML code wrapped in @startuml and @enduml tags.
        """
        for tag in ["member", "attribute"]:
            if not is_leaf_class(node_type, node_value_type):
                return False

        return True

    make_plant("root", "member")
    make_plant("none", "none")
    make_plant("member", "attribute")
    make_plant("none", "none")
